diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..ced0c2aa4443 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7768,9 +7768,50 @@ static Instruction *foldFCmpReciprocalAndZero(FCmpInst &I, Instruction *LHSI,
 /// Optimize fabs(X) compared with zero.
 static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
   Value *X;
-  if (!match(I.getOperand(0), m_FAbs(m_Value(X))))
-    return nullptr;
-
+  bool SafeForAllPredicates = false; // true if operand is fabs or select equivalent to fabs
+  if (match(I.getOperand(0), m_FAbs(m_Value(X)))) {
+    SafeForAllPredicates = true;
+  } else {
+    // Match select pattern where TrueVal and FalseVal are X and -X (either order).
+    Value *Cond, *TrueVal, *FalseVal;
+    if (!match(I.getOperand(0), m_Select(m_Value(Cond), m_Value(TrueVal), m_Value(FalseVal))))
+      return nullptr;
+    // Determine if TrueVal and FalseVal are X and -X.
+    if (match(FalseVal, m_FNeg(m_Specific(TrueVal)))) {
+      X = TrueVal;
+    } else if (match(TrueVal, m_FNeg(m_Specific(FalseVal)))) {
+      X = FalseVal;
+    } else {
+      return nullptr;
+    }
+    Value *MinusX = (X == TrueVal ? FalseVal : TrueVal);
+    // Check if condition is fcmp with zero and orientation matches fabs.
+    CmpInst::Predicate Pred;
+    Value *CmpLHS;
+    if (match(Cond, m_FCmp(Pred, m_Value(CmpLHS), m_AnyZeroFP()))) {
+      // Condition uses X (CmpLHS) and selects X when condition true?
+      // If CmpLHS == X and TrueVal == X, then select yields X when condition true.
+      // If CmpLHS == X and TrueVal == -X, then select yields -X when condition true.
+      // For fabs, we need predicate that yields non-negative result.
+      // Two patterns:
+      // 1. (X >= 0) ? X : -X  => predicate OGE/OGT/UGE/UGT, TrueVal == X
+      // 2. (X <= 0) ? -X : X  => predicate OLE/OLT/ULE/ULT, TrueVal == -X
+      if (CmpLHS == X) {
+        if (TrueVal == X &&
+            (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_OGT ||
+             Pred == FCmpInst::FCMP_UGE || Pred == FCmpInst::FCMP_UGT)) {
+          SafeForAllPredicates = true;
+        } else if (TrueVal == MinusX &&
+                   (Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_OLT ||
+                    Pred == FCmpInst::FCMP_ULE || Pred == FCmpInst::FCMP_ULT)) {
+          SafeForAllPredicates = true;
+        }
+      }
+    }
+    // If not SafeForAllPredicates, we must restrict to predicates where sign does not matter.
+    // That is equality and ordered/unordered predicates.
+    // We'll check later in the switch.
+  }
   const APFloat *C;
   if (!match(I.getOperand(1), m_APFloat(C)))
     return nullptr;

